queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?currency_exchange_service a :Currency_Exchange_Service .
    ?currency_exchange_service p:name ?name .
    ?currency_exchange_service p:Year_of_establishment ?year_of_establishment_f .
    FILTER((STR(?year_of_establishment_f) = "2000" || STR(?year_of_establishment_f) = "2000.0"))
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?commodity_trading_firm a :Commodity_Trading_Firm .
    ?commodity_trading_firm p:name ?name .
    ?commodity_trading_firm p:Year_of_establishment ?year_of_establishment_f .
    FILTER((STR(?year_of_establishment_f) = "2000" || STR(?year_of_establishment_f) = "2000.0"))
    BIND(?name AS ?o0)
  }
}

